SELECT AUDIT_MDL_CODE  AS auditModelNumber,
    /* 审计模型编码 */
       AUDIT_MDL_NAME  AS clueAuditModelName,
    /* 审计模型名称 */
       BRAE_PARTY      AS clueModelSupportParty,
    /* 支撑方 */
       AUDIT_CYCLE     AS clueAuditCycle,
    /* 审计周期 */
       MON_WARN_TIME   AS clueMonthlyAlarmTime,
    /* 每月告警时间 */
       AUDIT_MON       AS clueAuditMonth,
    /* 审计月 */
       DATA_MON        AS clueDataMonth,
    /* 数据月 */
       AUDIT_CLUE_CODE AS clueAuditCode,
    /* 审计线索编码 */
       AUDIT_CLUE_NAME AS clueAuditName,
    /* 审计线索名称 */
       AUDIT_CLUE_TYP  AS clueType,
    /* 线索类型 */
       AUDIT_CLUE_UNIT AS clueAuditUnit,
    /* 审计线索单位 */
       AUDIT_UNIT_CODE AS clueAuditedUnitCode,
    /* 被审计单位编码 */
       AUDIT_UNIT_NAME AS clueAuditedUnit,
    /* 被审计单位 */
       AUDIT_CLUE_VAL  AS clueQuantity,
    /* 线索量 */
       CLUE_CNT_RATE   AS clueQuantityRatio,
    /* 线索量占比 */
       CLUE_CNT_RANK   AS clueQuantityRank
    /* 线索量排名 */
FROM `tb_03`
where AUDIT_MDL_CODE is not null

SELECT AUDIT_MDL_CODE  AS clueAuditModelCode,
       AUDIT_MDL_CODE  AS auditModelNumber,
    /* 审计模型编码 */
       AUDIT_MDL_NAME  AS clueAuditModelName,
    /* 审计模型名称 */
       BRAE_PARTY      AS clueModelSupportParty,
    /* 支撑方 */
       AUDIT_CYCLE     AS clueAuditCycle,
    /* 审计周期 */
       MON_WARN_TIME   AS clueMonthlyAlarmTime,
    /* 每月告警时间 */
       AUDIT_MON       AS clueAuditMonth,
    /* 审计月 */
       DATA_MON        AS clueDataMonth,
    /* 数据月 */
       AUDIT_CLUE_CODE AS clueAuditCode,
    /* 审计线索编码 */
       AUDIT_CLUE_NAME AS clueAuditName,
    /* 审计线索名称 */
       AUDIT_CLUE_TYP  AS clueType,
    /* 线索类型 */
       AUDIT_CLUE_UNIT AS clueAuditUnit,
    /* 审计线索单位 */
       AUDIT_UNIT_CODE AS clueAuditedUnitCode,
    /* 被审计单位编码 */
       AUDIT_UNIT_NAME AS clueAuditedUnit,
    /* 被审计单位 */
       AUDIT_CLUE_VAL  AS clueQuantity,
    /* 线索量 */
       CLUE_CNT_RATE   AS clueQuantityRatio,
    /* 线索量占比 */
       CLUE_CNT_RANK   AS clueQuantityRank
    /* 线索量排名 */
FROM hpbus.TB_AUDIT_CLUE_LIBRARY_VT
WHERE AUDIT_MON = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMM')
  and AUDIT_MDL_CODE is not null
